verb :look() rxd {
  return { id: this, title: this.name, description: this.description, api_version: this.api_version, tools: ["inspect(id, opts?)", "search(query, opts?)", "create(parent, opts?)", "chparent(id, parent, opts?)", "recycle(id, opts?)", "set_property(id, name, value, opts?)"] };
}

verb :inspect(id, opts) rxd {
  // Builder surface check: wizard, or descendant of $builder.
  if (!has_flag(actor, "wizard")) {
    if (actor == $builder) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
    if (!isa(actor, $builder)) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
  }
  // Structure/data view: owner, flags, parent, children, instances, location,
  // contents, and property summaries. No source output.
  return authoring_inspect(id, opts, false);
}

verb :search(query, opts) rxd {
  if (!has_flag(actor, "wizard")) {
    if (actor == $builder) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
    if (!isa(actor, $builder)) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
  }
  // Bounded actor-scoped search across object names and property channels.
  // Source channels are reserved for the programmer surface.
  return authoring_search(query, opts, false);
}

verb :create(parent, opts) rxd {
  if (!has_flag(actor, "wizard")) {
    if (actor == $builder) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
    if (!isa(actor, $builder)) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
  }
  // Creates an object owned by the invoking actor. There is intentionally no
  // owner option on the builder surface; creating for another actor is wizard
  // administration, not delegated building.
  let result = builder_create_object(parent, opts);
  observe({ type: "builder_created", actor: actor, id: result["id"], parent: parent, ts: now() });
  return result;
}

verb :chparent(id, parent, opts) rxd {
  if (!has_flag(actor, "wizard")) {
    if (actor == $builder) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
    if (!isa(actor, $builder)) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
  }
  let result = builder_chparent(id, parent, opts);
  if (result["ok"] && !result["dry_run"]) {
    observe({ type: "builder_chparented", actor: actor, id: id, parent: parent, ts: now() });
  }
  return result;
}

verb :recycle(id, opts) rxd {
  // The substrate `recycle()` builtin gates on the verb's effective
  // principal (progr); this wrapper is catalog-owned, so progr is
  // wizard. Two layers of defense are needed.
  //
  // Layer 1 — actor-side authority gate (LambdaCore @recycle pattern):
  // route through the_perm so the auth rule lives in one place.
  "the_perm":requires_perm(actor, id, "only the owner or a wizard can recycle this object");
  // Layer 2 — strip user-intent wizard opts before forwarding. The
  // substrate also gates force_reserved on actor (defense in depth at
  // the substrate layer), but stripping here keeps the smuggle vector
  // out of the substrate's parser entirely. force_reserved is the
  // exclusive concern of $wiz:force_recycle.
  let safe_opts = {};
  if (typeof(opts) == "map") {
    for k in keys(opts) {
      if (k != "force_reserved") { safe_opts[k] = opts[k]; }
    }
  }
  let result = recycle(id, safe_opts);
  if (result["ok"] && !result["dry_run"]) {
    observe({ type: "builder_recycled", actor: actor, id: id, ts: now() });
  }
  return result;
}

verb :recycle_command(dobjstr) rxd {
  // LambdaCore $builder:@recycle (#630), faithfully ported. Divergences
  // (1)–(3) are called out where they appear; aside from those the verb
  // is line-for-line equivalent.
  if (typeof(dobjstr) != "string" || dobjstr == "") {
    tell(actor, "Usage: @recycle <object>");
    return null;
  }
  // L2 Original: dobj = player:my_match_object(dobjstr).
  // Divergence (1): woo's matcher is on $match (spec/semantics/match.md
  // MA1), not on the player; the MA2 resolution rule mirrors LambdaCore's
  // $string_utils:match_object.
  let dobj = $match:match_object(dobjstr);
  // L5-6 Original: $command_utils:object_match_failed handles both
  // sentinels with a notify-and-bail. Divergence (2): woo has no
  // $command_utils helper; the same logic is inline.
  if (dobj == $failed_match) {
    tell(actor, "I don't see '" + dobjstr + "' here.");
    return null;
  }
  if (dobj == $ambiguous_match) {
    tell(actor, "I don't know which '" + dobjstr + "' you mean.");
    return null;
  }
  // L7-8 Self-recycle. Original reads $wiz_utils.suicide_string; woo
  // doesn't carry that property, so a static line stands in.
  if (actor == dobj) {
    tell(actor, "You can't recycle yourself.");
    return null;
  }
  // L9-10 Original: !$perm_utils:controls(player, dobj) -> notify(E_PERM).
  // Divergence (3): woo routes the same owner-or-wizard rule through
  // the_perm so the auth gate lives in one place; the_perm raises E_PERM
  // and the chat layer renders it.
  "the_perm":requires_perm(actor, dobj, "only the owner or a wizard can recycle this object");
  // L1 set_task_perms(player) is omitted: woo's substrate authority gates
  // on `actor` and `progr` directly, and recycle() re-checks RC2 on entry.
  // L12-17 Capture name, recycle, notify with paste-able id.
  let name = dobj.name;
  let result = recycle(dobj, {});
  if (typeof(result) != "map" || !result["ok"]) {
    tell(actor, "Recycle failed: " + to_string(result));
    return result;
  }
  tell(actor, name + " (#" + dobj + ") recycled.");
  return result;
}

verb :set_property(id, name, value, opts) rxd {
  if (!has_flag(actor, "wizard")) {
    if (actor == $builder) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
    if (!isa(actor, $builder)) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
  }
  // Ordinary data value setting. This does not change verb source, property
  // perms, executable metadata, wizard/programmer flags, or ownership.
  return builder_set_property(id, name, value, opts);
}

verb :look() rxd {
  return { id: this, title: this.name, description: this.description, api_version: this.api_version, tools: ["inspect(id, opts?)", "resolve_verb(id, descriptor)", "list_verb(id, descriptor, opts?)", "search(query, opts?)", "install_verb(id, descriptor, source, opts?)", "set_verb_info(id, descriptor, opts?)", "set_property_info(id, name, opts?)", "edit_verb(id, descriptor, opts?)", "trace(id, descriptor, opts?)", "eval(source, opts?)", "force_recycle(id, opts?)  [wizard-only]"] };
}

verb :inspect(id, opts) rxd {
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!isa(actor, $programmer)) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!has_flag(actor, "programmer")) { raise { code: "E_PERM", message: "programmer flag required", value: actor }; }
  }
  // Source-aware call-tree view with read filters: parent/features walk, own
  // and inherited verbs/properties, slots, impact hints, and optional readable
  // source summaries. No bytecode.
  return authoring_inspect(id, opts, true);
}

verb :resolve_verb(id, descriptor) rxd {
  // Programmer surface check: wizard, or programmer-flagged descendant of
  // this surface class.
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) {
      raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } };
    }
    if (!isa(actor, $programmer)) {
      raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } };
    }
    if (!has_flag(actor, "programmer")) {
      raise { code: "E_PERM", message: "programmer flag required", value: actor };
    }
  }
  let walk = [];
  let definer = null;
  if (typeof(descriptor) == "number") {
    let own = verbs(id);
    let matched = false;
    if (descriptor >= 1) { if (descriptor <= length(own)) { matched = true; } }
    walk = walk + [{ id: id, kind: "slot", slot: descriptor, matched: matched }];
    if (!matched) {
      raise { code: "E_VERBNF", message: "verb slot not found", value: { obj: id, slot: descriptor, actor: actor } };
    }
    definer = id;
  } else {
    let chain = [id] + parents(id);
    for class_ref in chain {
      if (definer == null) {
        let class_verbs = verbs(class_ref);
        let class_match = false;
        for n in class_verbs { if (n == descriptor) { class_match = true; } }
        walk = walk + [{ id: class_ref, kind: "parent", matched: class_match }];
        if (class_match) { definer = class_ref; }
      }
    }
    if (definer == null) {
      raise { code: "E_VERBNF", message: "verb not found", value: { obj: id, name: descriptor, actor: actor } };
    }
  }
  let info = verb_info(definer, descriptor);
  let source = verb_code(definer, descriptor);
  return {
    name: info["name"],
    slot: info["slot"],
    aliases: info["aliases"],
    definer: definer,
    owner: info["owner"],
    perms: info["perms"],
    arg_spec: info["arg_spec"],
    version: info["version"],
    direct_callable: info["direct_callable"],
    tool_exposed: info["tool_exposed"],
    readable: true,
    source: source,
    line_map: {},
    walk: walk
  };
}

verb :list_verb(id, descriptor, opts) rxd {
  // Return readable source and metadata for one ordered verb slot. This is
  // source-level only: no bytecode, opcode, literal-pool, or VM detail.
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) {
      raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } };
    }
    if (!isa(actor, $programmer)) {
      raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } };
    }
    if (!has_flag(actor, "programmer")) {
      raise { code: "E_PERM", message: "programmer flag required", value: actor };
    }
  }
  let include_source = true;
  if (typeof(opts) == "map") { if (has(opts, "include_source")) { include_source = opts["include_source"]; } }
  let walk = [];
  let definer = null;
  if (typeof(descriptor) == "number") {
    let own = verbs(id);
    let matched = false;
    if (descriptor >= 1) { if (descriptor <= length(own)) { matched = true; } }
    walk = walk + [{ id: id, kind: "slot", slot: descriptor, matched: matched }];
    if (!matched) {
      raise { code: "E_VERBNF", message: "verb slot not found", value: { obj: id, slot: descriptor, actor: actor } };
    }
    definer = id;
  } else {
    let chain = [id] + parents(id);
    for class_ref in chain {
      if (definer == null) {
        let class_verbs = verbs(class_ref);
        let class_match = false;
        for n in class_verbs { if (n == descriptor) { class_match = true; } }
        walk = walk + [{ id: class_ref, kind: "parent", matched: class_match }];
        if (class_match) { definer = class_ref; }
      }
    }
    if (definer == null) {
      raise { code: "E_VERBNF", message: "verb not found", value: { obj: id, name: descriptor, actor: actor } };
    }
  }
  let info = verb_info(definer, descriptor);
  let result = {
    name: info["name"],
    slot: info["slot"],
    aliases: info["aliases"],
    definer: definer,
    owner: info["owner"],
    perms: info["perms"],
    arg_spec: info["arg_spec"],
    version: info["version"],
    direct_callable: info["direct_callable"],
    tool_exposed: info["tool_exposed"],
    readable: true,
    walk: walk
  };
  if (include_source) {
    result["source"] = verb_code(definer, descriptor);
    result["line_map"] = {};
  }
  return result;
}

verb :search(query, opts) rxd {
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!isa(actor, $programmer)) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!has_flag(actor, "programmer")) { raise { code: "E_PERM", message: "programmer flag required", value: actor }; }
  }
  // Bounded actor-scoped search. opts.channels may include readable
  // verb_source; unreadable source is omitted, not summarized.
  return authoring_search(query, opts, true);
}

verb :install_verb(id, descriptor, source, opts) rxd {
  // Programmer surface check.
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!isa(actor, $programmer)) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!has_flag(actor, "programmer")) { raise { code: "E_PERM", message: "programmer flag required", value: actor }; }
  }
  // Validate options. opts.perms is rejected — the source header is canonical.
  let dry_run = false;
  let mode = "upsert";
  let expected_version = null;
  if (typeof(opts) == "map") {
    if (has(opts, "perms")) {
      let fail_perms = { ok: false, dry_run: false, slot: 0, version: 0, diagnostics: [{ severity: "error", code: "E_INVARG", message: "opts.perms is not accepted; verb source header is canonical" }] };
      observe({ type: "programmer_check_failed", actor: actor, id: id, verb: descriptor, diagnostics: fail_perms["diagnostics"], dry_run: false, ts: now() });
      return fail_perms;
    }
    if (has(opts, "dry_run")) { dry_run = opts["dry_run"]; }
    if (has(opts, "mode")) { mode = opts["mode"]; }
    if (has(opts, "expected_version")) { expected_version = opts["expected_version"]; }
  }
  if (mode != "upsert" && mode != "define" && mode != "set_code") {
    raise { code: "E_INVARG", message: "unknown install mode", value: mode };
  }
  // Discover existing verb (own slot only).
  let existing = null;
  let existing_version = null;
  let existing_slot = 0;
  try {
    let info = verb_info(id, descriptor);
    existing = info;
    existing_version = info["version"];
    existing_slot = info["slot"];
  } except err { existing = null; }
  if (mode == "define" && existing != null) {
    raise { code: "E_INVARG", message: "verb already exists", value: { obj: id, descriptor: descriptor } };
  }
  if (mode == "set_code" && existing == null) {
    raise { code: "E_VERBNF", message: "verb not found", value: { obj: id, descriptor: descriptor } };
  }
  if (expected_version != null) {
    if (existing_version != expected_version) {
      raise { code: "E_VERSION", message: "verb version conflict", value: { expected: expected_version, actual: existing_version } };
    }
  }
  // Compile (pure, no mutation).
  let compiled = compile_verb(source);
  let target_name = descriptor;
  if (existing != null) { target_name = existing["name"]; }
  if (compiled["ok"]) {
    let meta = compiled["metadata"];
    if (meta != null && has(meta, "name")) {
      let header_name = meta["name"];
      if (typeof(header_name) == "string") {
        if (typeof(target_name) == "string" && header_name != target_name) {
          let fail_name = { ok: false, dry_run: dry_run, slot: existing_slot, version: existing_version, metadata: meta, diagnostics: [{ severity: "error", code: "E_COMPILE", message: "verb header :" + header_name + " does not match install target :" + target_name }] };
          observe({ type: "programmer_check_failed", actor: actor, id: id, verb: descriptor, diagnostics: fail_name["diagnostics"], dry_run: dry_run, ts: now() });
          return fail_name;
        }
      }
    }
  }
  if (!compiled["ok"]) {
    let fail_compile = { ok: false, dry_run: dry_run, slot: existing_slot, version: existing_version, metadata: compiled["metadata"], diagnostics: compiled["diagnostics"] };
    observe({ type: "programmer_check_failed", actor: actor, id: id, verb: descriptor, diagnostics: compiled["diagnostics"], dry_run: dry_run, ts: now() });
    return fail_compile;
  }
  // Predict the slot/version that the install would land on.
  let projected_slot = existing_slot;
  let projected_version = 1;
  if (existing != null) {
    projected_version = existing_version + 1;
  } else {
    projected_slot = length(verbs(id)) + 1;
  }
  if (dry_run) {
    return { ok: true, dry_run: true, slot: projected_slot, version: projected_version, metadata: compiled["metadata"], diagnostics: [] };
  }
  // Apply: create stub if needed, then install code.
  if (existing == null) {
    let add_info = { name: target_name };
    let add_meta = compiled["metadata"];
    if (add_meta != null) {
      if (has(add_meta, "perms")) { add_info["perms"] = add_meta["perms"]; }
      if (has(add_meta, "arg_spec")) { add_info["arg_spec"] = add_meta["arg_spec"]; }
    }
    add_verb(id, add_info);
  }
  let errors = set_verb_code(id, target_name, source);
  if (length(errors) > 0) {
    // Should not happen — compile_verb already succeeded — but if the
    // header/name post-validation rejects, roll back the stub.
    if (existing == null) { try { delete_verb(id, target_name); } except err { } }
    let diag = [];
    for msg in errors { diag = diag + [{ severity: "error", code: "E_COMPILE", message: msg }]; }
    observe({ type: "programmer_check_failed", actor: actor, id: id, verb: descriptor, diagnostics: diag, dry_run: false, ts: now() });
    return { ok: false, dry_run: false, slot: projected_slot, version: existing_version, metadata: compiled["metadata"], diagnostics: diag };
  }
  let info_after = verb_info(id, target_name);
  observe({ type: "programmer_installed", actor: actor, id: id, verb: descriptor, slot: info_after["slot"], version: info_after["version"], ts: now() });
  return { ok: true, dry_run: false, slot: info_after["slot"], version: info_after["version"], metadata: compiled["metadata"], diagnostics: [] };
}

verb :set_verb_info(id, descriptor, opts) rxd {
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!isa(actor, $programmer)) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!has_flag(actor, "programmer")) { raise { code: "E_PERM", message: "programmer flag required", value: actor }; }
  }
  // Metadata-only edit for aliases, arg spec, exposure flags, and perms.
  // Permission bits are changed here, not through source install. Does not
  // reinstall source. opts.dry_run=true validates without mutation.
  let dry_run = false;
  let expected_version = null;
  let info_overrides = {};
  if (typeof(opts) == "map") {
    if (has(opts, "dry_run")) { dry_run = opts["dry_run"]; }
    if (has(opts, "expected_version")) { expected_version = opts["expected_version"]; }
    if (has(opts, "aliases")) { info_overrides["aliases"] = opts["aliases"]; }
    if (has(opts, "perms")) { info_overrides["perms"] = opts["perms"]; }
    if (has(opts, "direct_callable")) { info_overrides["direct_callable"] = opts["direct_callable"]; }
    if (has(opts, "tool_exposed")) { info_overrides["tool_exposed"] = opts["tool_exposed"]; }
    if (has(opts, "arg_spec")) { info_overrides["arg_spec"] = opts["arg_spec"]; }
    if (has(opts, "owner")) { info_overrides["owner"] = opts["owner"]; }
  }
  let before = verb_info(id, descriptor);
  if (expected_version != null) {
    if (before["version"] != expected_version) {
      raise { code: "E_VERSION", message: "verb version conflict", value: { expected: expected_version, actual: before["version"] } };
    }
  }
  if (dry_run) {
    return { ok: true, dry_run: true, id: id, slot: before["slot"], version: before["version"] + 1, before: before, after: before };
  }
  let updated = set_verb_info(id, descriptor, info_overrides);
  let after = verb_info(id, descriptor);
  observe({ type: "programmer_verb_info_changed", actor: actor, id: id, verb: descriptor, slot: updated["slot"], version: updated["version"], ts: now() });
  return { ok: true, dry_run: false, id: id, slot: updated["slot"], version: updated["version"], before: before, after: after };
}

verb :set_property_info(id, name, opts) rxd {
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!isa(actor, $programmer)) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!has_flag(actor, "programmer")) { raise { code: "E_PERM", message: "programmer flag required", value: actor }; }
  }
  // Define/update property metadata, defaults, perms, and type hints. This is
  // programmer authority, not the builder value-setting surface.
  let dry_run = false;
  let mode = "upsert";
  if (typeof(opts) == "map") {
    if (has(opts, "dry_run")) { dry_run = opts["dry_run"]; }
    if (has(opts, "mode")) { mode = opts["mode"]; }
  }
  if (mode != "upsert" && mode != "define" && mode != "update" && mode != "delete") {
    raise { code: "E_INVARG", message: "unknown property-info mode", value: mode };
  }
  let existing = null;
  try { existing = property_info(id, name); } except err { existing = null; }
  // The substrate raises E_PROPNF when looking up a non-defined property; if
  // the def lives on a parent class, property_info still returns it. For mode
  // semantics we want to treat "defined on this object directly" as the
  // existence test.
  let exists_locally = false;
  if (existing != null) {
    if (existing["defined_on"] == id) { exists_locally = true; }
  }
  if (mode == "define" && exists_locally) {
    raise { code: "E_INVARG", message: "property already exists", value: { obj: id, property: name } };
  }
  if ((mode == "update" || mode == "delete") && !exists_locally) {
    raise { code: "E_PROPNF", message: "property not defined on object", value: { obj: id, property: name } };
  }
  if (mode == "delete") {
    let delete_before = existing;
    if (dry_run) { return { ok: true, dry_run: true, id: id, name: name, deleted: true, before: delete_before }; }
    set_task_perms(actor);
    delete_property(id, name);
    return { ok: true, dry_run: false, id: id, name: name, deleted: true, before: delete_before };
  }
  let perms_opt = "rw";
  if (existing != null) { perms_opt = existing["perms"]; }
  let owner_opt = actor;
  if (existing != null) { owner_opt = existing["owner"]; }
  let type_opt = null;
  if (existing != null) { type_opt = existing["type_hint"]; }
  let default_value = null;
  if (typeof(opts) == "map") {
    if (has(opts, "perms")) { perms_opt = opts["perms"]; }
    if (has(opts, "owner")) { owner_opt = opts["owner"]; }
    if (has(opts, "type_hint")) { type_opt = opts["type_hint"]; }
    if (has(opts, "default")) { default_value = opts["default"]; }
  }
  let info_map = { owner: owner_opt, perms: perms_opt };
  if (type_opt != null) { info_map["type_hint"] = type_opt; }
  let before = existing;
  if (dry_run) {
    let projected = { name: name, owner: owner_opt, perms: perms_opt, defined_on: id, type_hint: type_opt };
    return { ok: true, dry_run: true, id: id, name: name, before: before, after: projected };
  }
  set_task_perms(actor);
  if (!exists_locally) {
    add_property(id, name, default_value, info_map);
  } else {
    set_property_info(id, name, info_map);
  }
  let after = property_info(id, name);
  return { ok: true, dry_run: false, id: id, name: name, version: after["version"], before: before, after: after };
}

